INSERT INTO questions (question, option1, option2, option3, option4, correct_answers, category, is_multiple_choice) VALUES
('1 or 0? Each AWS region is designed to be completely isolated from the other AWS regions', '1', '0', '', '', 0, 'aws', 0),
('1 or 0? Each region has a minimum number of 1 availability zones and the maximum is 4', '1', '0', '', '', 1, 'aws', 0),
('What considerations to take when choosing an AWS region for running a new application?', 'The region with most number of Availability Zones', 'The region closest to the AWS global headquarters', 'The region that minimizes latency for your users and complies with data residency regulations', 'The region with the cheapest EC2 pricing overall', 2, 'aws', 0),
('1 or 0? IAM configuration is defined globally and not per region', '1', '0', '', '', 0, 'aws', 0),
('1 or 0? When creating an AWS account, root account is created by default. This is the recommended account to use and share in your organization', '1', '0', '', '', 1, 'aws', 0),
('1 or 0? Groups in AWS IAM, can contain only users and no other groups', '1', '0', '', '', 0, 'aws', 0),
('1 or 0? Users in AWS IAM, can belong only to a single group', '1', '0', '', '', 1, 'aws', 0),
('What is AWS Identity and Access Management (IAM), and which of the following is a feature it provides?', 'It manages EC2 instance performance optimization', 'It provides a firewall to block malicious traffic', 'It allows you to manage access to AWS services and resources securely', 'It is used to automatically scale applications across regions', 2, 'aws', 0),
("1 or 0? If a user in AWS is using password for authenticating, he doesn't needs to enable MFA", '1', '0', '', '', 1, 'aws', 0),
('Which of the following best characterizes the purpose of an IAM Role in AWS?', 'A permanent identity assigned to users for long-term access to AWS services', 'A temporary set of permissions that can be assumed by trusted entities such as AWS services.', 'A mechanism for grouping IAM users under a common set of policies', 'A script used for provisioning access control lists to AWS resources', 1, 'aws', 0),
('In the context of AWS IAM, which of the following statements most accurately describes what a policy is?', 'A YAML-based document that controls access to AWS billing features', 'A configuration file attached to resources that defines their behavior', 'A JSON document that specifies who can assume an IAM role', 'A JSON-based permission document that defines what actions are allowed or denied on specific AWS resources', 3, 'aws', 0),
('A user is unable to access an s3 bucket. What might be the problem?', 'Move the S3 bucket to the user’s default region', 'Attach a policy to the user granting permissions to access the S3 bucket', 'Modify the bucket’s ACL to grant the user read permissions', 'Enable S3 Block Public Access settings on the bucket', 1, 'aws', 0),
('1 or 0? EC2 is a regional service', '1', '0', '', '', 0, 'aws', 0),
('1 or 0? AMI are built for specific region', '1', '0', '', '', 0, 'aws', 0),
('In the EC2 instance type name m5.large, what does each component represent?', 'M = Generation 5=Instance Class, Large=Storage Size', 'M = Memory Optimized, 5 = Burstable performance tier, Large = network throughput', 'M = Instance Class, 5 = Generation, Large = Size of the instance', 'M = Reserved Instance Type, 5 = core count, Large = EBS Volume size', 2, 'aws', 0),
('1 or 0? The following are instance types available for a user in AWS:', 'Compute optimized', 'Network optimized', 'Web Optimized', '', 2, 'aws', 0),
('What happens to EBS volumes when an EC2 instance is terminated?', 'All attached EBS volumes are deleted immediately by default.', 'By default, the root volume is deleted, but any additional EBS volumes persist unless specified otherwise.', 'By default, both the root and any additional EBS volumes are preserved.', 'All EBS volumes, including snapshots, are retained and billed until manually deleted.', 1, 'aws', 0),
('What happens to the attached EBS volumes when an EC2 instance is stopped (not terminated)?', 'All EBS volumes are deleted, including the root volume', 'The root volume is deleted, but data volumes remain intact', 'The EBS volumes are detached and archived to S3', 'The EBS volumes remain intact and will be available when the instance is started again', 3, 'aws', 0),
('1 or 0? EBS volumes are locked to a specific availability zone', '1', '0', '', '', 0, 'aws', 0),
('What are the use cases for using EBS snapshots?', 'Create a point-in-time copy of an EBS volume that can be used to create a new volume in a different Availability Zone or Region.', 'Immediately restore an EBS volume to a previous state without any downtime.', 'Provide a continuous, real-time backup of an EBS volume.', 'Directly replace a failed EBS volume with a snapshot without any data loss or service interruption.', 0, 'aws', 0),
('Under what condition can a single EBS volume be attached to multiple EC2 instances simultaneously?', 'When using Provisioned IOPS SSD (io1 or io2) volumes with Multi-Attach enabled', 'When using general purpose SSD (gp3) volumes', 'When using standard magnetic volumes', 'When launching instances in the same Availability Zone without IAM restrictions', 0, 'aws', 0),
('1 or 0? EBS is a network drive hence, it requires network connectivity', '1', '0', '', '', 0, 'aws', 0),
('1 or 0? EFS is locked into a single availability zone', '1', '0', '', '', 1, 'aws', 0),
('Which of the following are common use cases for using Amazon EFS (Elastic File System)?', 'Hosting container images and AMIs for reuse across Regions', 'Data sharing, web serving, and content management across multiple EC2 instances', 'Temporary high-speed block storage for individual EC2 instances', 'Object-level storage for static websites with global access', 1, 'aws', 0),
('1 or 0? EFS only compatible with Linux based AMI', '1', '0', '', '', 0, 'aws', 0),
("1 or 0? EFS requires the user to perform capacity planning as it doesn't scales automatically", '1', '0', '', '', 1, 'aws', 0),
('1 or 0? Reserved instance has to be used for a minimum of 1 year', '1', '0', '', '', 0, 'aws', 0),
('You need to launch an EC2 instance for a short-term project, and it is critical that the workload is not interrupted. Which EC2 pricing model is the most appropriate?', 'Reserved Instances', 'Spot Instances', 'On-Demand Instances', 'Savings Plans', 2, 'aws', 0),
('1 or 0? One security group can be attached to multiple instances', '1', '0', '', '', 0, 'aws', 0),
('1 or 0? Security groups are not locked down to a region and VPC', '1', '0', '', '', 1, 'aws', 0),
("In the context of AWS EC2, what does 'bootstrapping' refer to and how is it typically used?", 'Encrypting the EBS volumes before launching the instance', 'Creating a snapshot of the root volume before instance shutdown', 'Attaching IAM roles to an instance for temporary access credentials', 'Automatically configuring an instance at launch using user data scripts', 3, 'aws', 0),
("1 or 0? It's possible to have multiple VPCs in one region", '1', '0', '', '', 0, 'aws', 0),
('1 or 0? One or more VPCs can be attached to one Internet Gateway', '1', '0', '', '', 1, 'aws', 0),
('After restarting your EC2 instance, you notice that the public IP address has changed. How can you ensure the IP address remains the same across restarts?', 'Use an Elastic Load Balancer (ELB) in front of the instance', 'Stop using public IPs and switch to private IPs only', 'Assign an Elastic IP to the instance', 'Change the instance type to a reserved instance', 2, 'aws', 0),
("1 or 0? In AWS Lambda, you are charged as long as a function exists, regardless of whether it's running or not", '1', '0', '', '', 1, 'aws', 0),
('1 or 0? Basic lambda permissions allow you only to upload logs to Amazon CloudWatch Logs', '1', '0', '', '', 0, 'aws', 0),
('What must be done to make an EC2 instance part of an Amazon ECS (Elastic Container Service) cluster?', 'Attach an IAM role with read-only S3 permissions', 'Install the ECS agent and configure the instance to join the cluster', 'Enable auto-scaling on the EC2 instance', 'Convert the EC2 instance to a Lambda function', 1, 'aws', 0),
('What features suits CloudWatch operation?', 'CloudWatch does not support custom metrics', 'collect and monitor operating system and application generated log files', 'CloudTrail generates logs automatically when AWS account is activated', 'AWS services automatically create logs for CloudWatch', 1, 'aws', 0),
('What is required to ensure that new EC2 instances launched by an Auto Scaling Group are correctly configured?', 'Tagging the instances with a specific key', 'Creating a CloudFormation template', 'Defining a Launch Template', 'Enabling S3 bucket access on the instance', 2, 'aws', 0),
('What happens when an EC2 instance registered with an ELB through an ASG fails its health check?', 'ELB will reboot the instance automatically', 'The instance will be manually deregistered by AWS support', 'ELB will send an SNS alert but take no action', 'ASG will terminate the instance and launch a new one', 3, 'aws', 0),
('1 or 0? RDS read replicas are asynchronous?', '1', '0', '', '', 0, 'aws', 0),
('1 or 0? Amazon RDS supports MongoDB?', '1', '0', '', '', 1, 'aws', 0),
